mapper.select:
SELECT count(*)
FROM hm_query.fact_payments fp
LEFT JOIN hm_query.dim_customer dc ON fp.customer_id = dc.customer_id
LEFT JOIN hm_query.dim_payment_method dpm ON fp.payment_method = dpm.method_code

    AND fp.order_id = #{orderId}
    AND fp.customer_id = #{customerId}
    AND fp.payment_method = #{paymentMethod}
    AND fp.state_id = #{stateId}
    AND fp.currency = #{currency}
    AND (
        fp.order_id LIKE CONCAT('%', #{q}, '%')
        OR dc.customer_name LIKE CONCAT('%', #{q}, '%')
        OR fp.gateway_transaction_id LIKE CONCAT('%', #{q}, '%')
    )

SELECT fp.id as "id", fp.order_id as "orderId", fp.customer_id as "customerId", dc.customer_name as "customerName", fp.amount as "amount", fp.currency as "currency", fp.payment_method as "paymentMethod", dpm.method_display_name as "paymentMethodDisplay", fp.gateway_transaction_id as "gatewayTransactionId", fp.retry_count as "retryCount", fp.failure_reason as "failureReason", fp.state_id as "stateId", fp.flow_id as "flowId", fp.created_time as "createdTime" FROM hm_query.fact_payments fp LEFT JOIN hm_query.dim_customer dc ON fp.customer_id = dc.customer_id LEFT JOIN hm_query.dim_payment_method dpm ON fp.payment_method = dpm.method_code
AND fp.order_id = #{orderId} AND fp.customer_id = #{customerId} AND fp.payment_method = #{paymentMethod} AND fp.state_id = #{stateId} AND fp.currency = #{currency} AND ( fp.order_id LIKE CONCAT('%', #{q}, '%') OR dc.customer_name LIKE CONCAT('%', #{q}, '%') OR fp.gateway_transaction_id LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}

SELECT count(*) FROM hm_query.payment_refunds_flat

    AND payment_id = #{paymentId}
    AND status = #{status}

SELECT id as "id", payment_id as "paymentId", amount as "amount", reason as "reason", status as "status", created_time as "createdTime" FROM hm_query.payment_refunds_flat
AND payment_id = #{paymentId} AND status = #{status}
${orderby} ${pagination}

SELECT count(*) FROM hm_query.payment_webhook_log_flat

    AND payment_id = #{paymentId}
    AND event_type = #{eventType}
    AND provider = #{provider}
    AND status = #{status}

SELECT
    id             as "id",
    payment_id     as "paymentId",
    event_type     as "eventType",
    provider       as "provider",
    status         as "status",
    created_time   as "createdTime"
FROM hm_query.payment_webhook_log_flat

    AND payment_id = #{paymentId}
    AND event_type = #{eventType}
    AND provider = #{provider}
    AND status = #{status}

${orderby} ${pagination}
